function toAbortError(reason, message = 'Aborted') {
  if (reason && reason.name === 'AbortError') return reason;
  const err = new Error(reason && reason.message ? reason.message : message);
  err.name = 'AbortError';
  return err;
}

export default function pollUntil(check, options = {}) {
  const { interval = 50, timeout, signal } = options;

  return new Promise((resolve, reject) => {
    let retryTimerId;
    let deadlineTimerId;
    let settled = false;

    const cleanup = () => {
      if (retryTimerId !== undefined) clearTimeout(retryTimerId);
      if (deadlineTimerId !== undefined) clearTimeout(deadlineTimerId);
      if (signal) signal.removeEventListener('abort', onAbort);
    };

    const settle = (callback, value) => {
      if (settled) return false;
      settled = true;
      cleanup();
      callback(value);
      return true;
    };

    const onAbort = () => {
      settle(reject, toAbortError(signal && signal.reason));
    };

    if (signal) {
      if (signal.aborted) {
        settle(reject, toAbortError(signal.reason));
        return;
      }
      signal.addEventListener('abort', onAbort, { once: true });
    }

    if (timeout != null) {
      deadlineTimerId = setTimeout(() => {
        settle(reject, new Error('Timeout'));
      }, Math.max(0, timeout));
    }

    const attempt = async () => {
      if (settled) return;

      try {
        const result = await check();
        if (settled) return;
        if (result) {
          settle(resolve, result);
          return;
        }
      } catch (err) {
        if (settled) return;
        settle(reject, err);
        return;
      }

      if (settled) return;
      retryTimerId = setTimeout(attempt, interval);
    };

    attempt();
  });
}
